:root {
  --bg: #0d1117;
  --card: #161b22;
  --border: #30363d;
  --text: #c9d1d9;
  --muted: #8b949e;
}

body {
  background: var(--bg);
  color: var(--text);
  font-family: "Inter", sans-serif;
  padding: 15px;
  margin: 0;
}

.report-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 20px;
  border-bottom: 1px solid var(--border);
  padding-bottom: 15px;
}

.brand h1 {
  font-size: 18px;
  margin: 0;
  color: #fff;
}

.brand p {
  font-size: 10px;
  color: var(--muted);
  text-transform: uppercase;
  margin: 4px 0 0;
}

.tab-controls {
  background: #21262d;
  padding: 4px;
  border-radius: 6px;
  display: flex;
  gap: 4px;
}

.tab-btn {
  background: none;
  border: none;
  color: var(--muted);
  padding: 6px 12px;
  border-radius: 4px;
  font-size: 11px;
  font-weight: 600;
  cursor: pointer;
}

.tab-btn.active {
  background: #30363d;
  color: #fff;
}

.kpi-row {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
  margin-bottom: 15px;
}

.kpi-box {
  background: var(--card);
  border: 1px solid var(--border);
  padding: 12px;
  border-radius: 8px;
}

.kpi-box span {
  font-size: 9px;
  color: var(--muted);
  text-transform: uppercase;
  font-weight: 700;
}

.kpi-box h2 {
  font-size: 20px;
  margin: 4px 0 0;
}

.tab-pane {
  display: none;
}

.tab-pane.active {
  display: block;
}

.card-viz {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 15px;
  margin-bottom: 15px;
}

.viz-title {
  font-size: 11px;
  color: var(--muted);
  text-transform: uppercase;
  margin-bottom: 15px;
  font-weight: 700;
}

.composition-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 15px;
}

.statement-card {
  background: #fff;
  color: #000;
  border-radius: 4px;
}

.statement-title {
  background: #f6f8fa;
  padding: 12px 20px;
  font-size: 13px;
  font-weight: 700;
  border-bottom: 1px solid #d0d7de;
}

.statement-scroll {
  max-height: 550px;
  overflow-y: auto;
  padding: 20px;
}

.report-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 11px;
  margin-bottom: 20px;
}

.report-table th {
  background: #f6f8fa;
  text-align: left;
  padding: 8px;
  border-bottom: 2px solid #d0d7de;
}

.report-table td {
  padding: 8px;
  border-bottom: 1px solid #ebf0f4;
}

.loader {
  padding: 40px;
  text-align: center;
  color: var(--muted);
}

