let charts = {};
const f = v => new Intl.NumberFormat('en-IN', {
  style: 'currency',
  currency: 'INR',
  maximumFractionDigits: 0
}).format(v);

// Self-starting logic
setTimeout(() => {
  if (appsmith.model.report) update(appsmith.model.report);
}, 500);
appsmith.onModelUpdate(() => {
  if (appsmith.model.report) update(appsmith.model.report);
});
function update(weeks) {
  if (!weeks || weeks.length === 0) return;
  let totalIn = 0,
    totalOut = 0,
    transCount = 0;
  const timeline = {
    labels: [],
    inflow: [],
    outflow: []
  };

  // Process Hierarchical Data
  weeks.forEach(week => {
    totalIn += parseFloat(week.total_in || 0);
    totalOut += parseFloat(week.total_out || 0);
    (week.days || []).forEach(day => {
      timeline.labels.push(day.display_date.replace(' 2026', ''));
      timeline.inflow.push(parseFloat(day.total_in));
      timeline.outflow.push(parseFloat(day.total_out));
      day.categories.forEach(cat => transCount += cat.transactions.length);
    });
  });

  // Update KPIs
  document.getElementById('val-in').innerText = f(totalIn);
  document.getElementById('val-out').innerText = f(totalOut);
  document.getElementById('val-net').innerText = f(totalIn - totalOut);
  document.getElementById('val-velocity').innerText = transCount + " Events";
  document.getElementById('sync-status').innerText = "Last Sync: " + new Date().toLocaleTimeString();

  // Render Journey List
  renderJourney(weeks);

  // Render Visuals
  updateChart(timeline);
}
function renderJourney(weeks) {
  const root = document.getElementById('journey-root');
  root.innerHTML = weeks.map(week => `
        <div class="week-item">
            <div class="week-head">
                <span>Week: ${week.label}</span>
                <span style="color: var(--accent-in)">+${f(week.total_in)}</span>
            </div>
            ${week.days.map(day => `
                <div class="day-item">
                    <div class="day-title">${day.display_date} • Day Net: ${f(day.total_in - day.total_out)}</div>
                    ${day.categories.map(cat => `
                        <div style="margin-bottom: 12px;">
                            <div style="font-size: 9px; color: var(--text-secondary); text-transform: uppercase; margin-bottom: 5px;">${cat.label}</div>
                            ${cat.transactions.map(t => `
                                <div class="trans-row">
                                    <div>
                                        <div class="trans-party">${t.party_name}</div>
                                        <div class="trans-desc">${t.description || ''} • ${t.db_ref}</div>
                                    </div>
                                    <div class="amt ${t.amount_in > 0 ? 'in' : 'out'}">
                                        ${t.amount_in > 0 ? '+' + f(t.amount_in) : '-' + f(t.amount_out)}
                                    </div>
                                </div>
                            `).join('')}
                        </div>
                    `).join('')}
                </div>
            `).join('')}
        </div>
    `).join('');
}
function updateChart(data) {
  const ctx = document.getElementById('mainChart').getContext('2d');
  if (charts.trend) charts.trend.destroy();

  // Reverse arrays to show earliest to latest (left to right)
  const labels = [...data.labels].reverse();
  const inflow = [...data.inflow].reverse();
  const outflow = [...data.outflow].reverse();
  charts.trend = new Chart(ctx, {
    type: 'line',
    data: {
      labels: labels,
      datasets: [{
        label: 'Inflow',
        data: inflow,
        borderColor: '#3fb950',
        backgroundColor: 'rgba(63, 185, 80, 0.1)',
        fill: true,
        tension: 0.4,
        borderWidth: 2,
        pointRadius: 2
      }, {
        label: 'Outflow',
        data: outflow,
        borderColor: '#f85149',
        backgroundColor: 'rgba(248, 81, 73, 0.05)',
        fill: false,
        tension: 0.4,
        borderWidth: 2,
        pointRadius: 2
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: {
        legend: {
          labels: {
            color: '#8b949e',
            font: {
              size: 10
            }
          }
        }
      },
      scales: {
        y: {
          grid: {
            color: 'rgba(255,255,255,0.05)'
          },
          ticks: {
            color: '#8b949e',
            font: {
              size: 10
            },
            callback: v => '₹' + v / 1000 + 'k'
          }
        },
        x: {
          grid: {
            display: false
          },
          ticks: {
            color: '#8b949e',
            font: {
              size: 10
            }
          }
        }
      }
    }
  });
}

